12	@Processor('jira')
13	export class JiraProcessor extends WorkerHost {
14		private readonly logger = new Logger(JiraProcessor.name);
15	
16		constructor(private readonly syncService: JiraSyncService) {
17			super();
18		}
19	
20		async process(
21			job: Job<IDiscoverProjectsJob | ISyncProjectJob | IPollInstallationsJob>,
22		): Promise<void> {
23			try {
24				if (job.name === 'poll_installations') {
25					await this.syncService.pollAllInstallations();
26					return;
27				}
28	
29				if (job.name === 'discover_projects') {
30					const data = job.data as IDiscoverProjectsJob;
31					await this.syncService.discoverProjects({
32						installationDbId: data.installationDbId,
33					});
34					return;
35				}
36	
37				if (job.name === 'sync_project') {
38					const data = job.data as ISyncProjectJob;
39					await this.syncService.syncProject({
40						installationDbId: data.installationDbId,
41						projectDbId: data.projectDbId,
42						projectKey: data.projectKey,
43					});
44					return;
45				}
46	
47				this.logger.warn(`Unknown job type: ${job.name}`);
48			} catch (error) {
49				this.logger.error(
50					`Job ${job.name} (${job.id}) failed: ${(error as Error).message}`,
51				);
52				throw error;
53			}
54		}
55	
56		@OnWorkerEvent('completed')
57		onCompleted({ id, name }: Job): void {
58			this.logger.debug(`Job ${name} (${id}) completed`);
59		}
60	}
