43	@Processor('github')
44	export class GithubEventProcessor extends WorkerHost {
45		private readonly logger = new Logger(GithubEventProcessor.name);
46	
47		constructor(
48			private readonly installationModel: GithubInstallationModel,
49			private readonly repoModel: GithubRepoModel,
50			private readonly contributorModel: GithubContributorModel,
51			private readonly commitModel: GithubCommitModel,
52			private readonly pullRequestModel: GithubPullRequestModel,
53			private readonly reviewModel: GithubReviewModel,
54			private readonly reviewCommentModel: GithubReviewCommentModel,
55			private readonly githubAppService: GithubAppService,
56			private readonly httpService: HttpService,
57		) {
58			super();
59		}
