61		async process(job: Job<IRawEventJob>): Promise<void> {
62			if (job.name === 'backfill_repo') {
63				await this.handleBackfillRepo({ data: job.data as unknown as IBackfillRepoJob });
64				return;
65			}
66			if (job.name !== 'raw_event') return;
67	
68			const { event, installationId, payload } = job.data;
69	
70			try {
71				const installation = await this.installationModel.findByInstallationId({
72					installationId,
73				});
74	
75				if (!installation) {
76					this.logger.warn(`No installation found for installationId: ${installationId}`);
77					return;
78				}
79	
80				switch (event) {
81					case 'push':
82						await this.handlePush({
83							installationDbId: installation._id,
84							payload: payload as IGithubWebhookPushEvent,
85						});
86						break;
87					case 'pull_request':
88						await this.handlePullRequest({
89							installationDbId: installation._id,
90							payload: payload as IGithubWebhookPREvent,
91						});
92						break;
93					case 'pull_request_review':
94						await this.handleReview({
95							installationDbId: installation._id,
96							payload: payload as IGithubWebhookReviewEvent,
97						});
98						break;
99					case 'pull_request_review_comment':
100						await this.handleReviewComment({
101							installationDbId: installation._id,
102							payload: payload as IGithubWebhookReviewCommentEvent,
103						});
104						break;
105					case 'installation_repositories':
106						await this.handleInstallationRepositories({
107							installationDbId: installation._id,
108							payload: payload as IGithubInstallationRepositoriesEvent,
109						});
110						break;
111					default:
112						this.logger.debug(`Unhandled event type: ${event}`);
113				}
114			} catch (error) {
115				this.logger.error(
116					`Failed to process ${event} event for installation ${installationId}: ${(error as Error).message}`,
117				);
118				throw error;
119			}
120		}
