204					pr_number: pr.number,
205					title: pr.title,
206					state: pr.state as GithubPRState,
207					author_login: pr.user.login,
208					draft: pr.draft,
209					merged: pr.merged,
210					additions: pr.additions,
211					deletions: pr.deletions,
212					changed_files: pr.changed_files,
213					commits_count: pr.commits,
214					opened_at: new Date(pr.created_at),
