221		private async handleReview({
222			installationDbId,
223			payload,
224		}: {
225			installationDbId: string;
226			payload: IGithubWebhookReviewEvent;
227		}): Promise<void> {
228			const repo = await this.repoModel.findByGithubRepoId({
229				githubRepoId: payload.repository.id,
230			});
231	
232			if (!repo) return;
233	
234			const pullRequest = await this.pullRequestModel.findByRepoAndNumber({
235				repoId: repo._id,
236				prNumber: payload.pull_request.number,
237			});
238	
239			if (!pullRequest) {
240				this.logger.warn(
241					`Pull request #${payload.pull_request.number} not found for repo ${repo._id}`,
242				);
243				return;
244			}
245	
246			const normalizedState = payload.review.state.toLowerCase();
247			const validStates: string[] = [
248				GithubReviewState.APPROVED,
249				GithubReviewState.CHANGES_REQUESTED,
250				GithubReviewState.COMMENTED,
251				GithubReviewState.DISMISSED,
252			];
253	
254			if (!validStates.includes(normalizedState)) return;
255	
256			await this.contributorModel.upsert({
257				data: {
258					installation_id: installationDbId,
259					github_user_id: payload.review.user.id,
260					github_login: payload.review.user.login,
261				},
262			});
263	
264			await this.reviewModel.upsert({
265				data: {
266					installation_id: installationDbId,
267					pull_request_id: pullRequest._id,
268					github_review_id: payload.review.id,
269					reviewer_login: payload.review.user.login,
270					state: normalizedState as GithubReviewState,
271					submitted_at: new Date(payload.review.submitted_at),
272				},
273			});
274		}
