347		private async handleBackfillRepo({ data }: { data: IBackfillRepoJob }): Promise<void> {
348			const { installationDbId, installationId, repoDbId, repoFullName } = data;
349			this.logger.debug(`Starting backfill for repo ${repoFullName}`);
350			const token = await this.githubAppService.getInstallationToken({ installationId });
351			const parts = repoFullName.split('/');
352			const owner = parts[0] ?? '';
353			const repo = parts[1] ?? '';
354			await this.backfillCommits({
355				installationDbId,
356				repoDbId,
357				repoFullName,
358				owner,
359				repo,
360				token,
361			});
362			await this.backfillPullRequests({
363				installationDbId,
364				repoDbId,
365				repoFullName,
366				owner,
367				repo,
368				token,
369			});
370			this.logger.debug(`Backfill complete for repo ${repoFullName}`);
371		}
