373		private async backfillCommits({
374			installationDbId,
375			repoDbId,
376			repoFullName,
377			owner,
378			repo,
379			token,
380		}: {
381			installationDbId: string;
382			repoDbId: string;
383			repoFullName: string;
384			owner: string;
385			repo: string;
386			token: string;
387		}): Promise<void> {
388			let page = 1;
389			const perPage = 100;
390			while (true) {
391				const { data: commits } = await this.httpService.axiosRef.get<IGithubApiCommit[]>(
392					`https://api.github.com/repos/${owner}/${repo}/commits`,
393					{
394						headers: {
395							Authorization: `token ${token}`,
396							Accept: 'application/vnd.github+json',
397							'X-GitHub-Api-Version': '2022-11-28',
398						},
399						params: { per_page: perPage, page },
400					},
401				);
402				if (commits.length === 0) break;
403				await this.commitModel.upsertMany({
404					commits: commits.map((c) => ({
405						installation_id: installationDbId,
406						repo_id: repoDbId,
407						sha: c.sha,
408						message: c.commit.message,
409						author_login: c.author?.login ?? null,
410						author_name: c.commit.author.name,
411						author_email: c.commit.author.email,
412						committed_at: new Date(c.commit.author.date),
413						additions: c.stats?.additions ?? 0,
414						deletions: c.stats?.deletions ?? 0,
415						is_merge_commit: c.parents.length > 1,
416					})),
417				});
418				if (commits.length < perPage) break;
419				page++;
420			}
421			this.logger.debug(`Backfilled commits for ${repoFullName}`);
422		}
